def gen(rng, size):
    n = max(1, min(size, 100000))
    nums = []
    for i in range(n):
        if i % 2 == 0:
            nums.append(rng.randint(500000000, 1000000000))
        else:
            nums.append(rng.randint(1, 500000000))
    return [nums]

