class Solution:
    def minOperations(self, nums):
        n = len(nums)
        target = [0] * n
        target[0] = nums[0]
        for i in range(1, n):
            target[i] = nums[i] if nums[i] > target[i - 1] else target[i - 1]
        delta = [target[i] - nums[i] for i in range(n)]
        total = 0
        prev = 0
        for d in delta:
            if d > prev:
                total += d - prev
            prev = d
        return total

