class Solution:
    def minOperations(self, nums: list[int]) -> int:
        cur_max = nums[0]
        delta_prev = 0
        cost = 0
        for i in range(1, len(nums)):
            t = nums[i] if nums[i] > cur_max else cur_max
            d = t - nums[i]
            if d > delta_prev:
                cost += d - delta_prev
            cur_max = t
            delta_prev = d
        return cost

