var minOperations = function(nums) {
    let curMax = nums[0];
    let deltaPrev = 0;
    let cost = 0;
    for (let i = 1; i < nums.length; i++) {
        const t = nums[i] > curMax ? nums[i] : curMax;
        const d = t - nums[i];
        if (d > deltaPrev) {
            cost += d - deltaPrev;
        }
        curMax = t;
        deltaPrev = d;
    }
    return cost;
};
